// // This module calculates the absolute value of a 16-bit signed integer input. If the input is positive, it generates the output as the two's complement of the input; otherwise, it directly outputs the input value.
module top_module(
    input signed [15:0] in,
    output reg [15:0] out
);always @(*) begin
        if (in < 0) begin
            out = ~in + 1;
        end else begin
            out = in;
        end
    end

endmodule
